def classify(text):
    text = text.lower()
    scores = {cat: 0 for cat in keywords}

    # Check phrases first (stronger signal)
    for cat, ph_list in phrases.items():
        for ph in ph_list:
            if ph in text:
                scores[cat] += 5

    # Check words
    words = re.findall(r'\w+', text)
    for word in words:
        for cat, kws in keywords.items():
            if word in kws:
                scores[cat] += 1

    # Penalty/Adjustments
